import{_ as d,o as e,c as o,ag as a}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Find-псевдонимы | Dotfiles (RU)","titleTemplate":":title","description":"Оптимизируйте поиск файлов с помощью псевдонимов на основе fd. Быстрый, цветной вывод и интуитивные команды для Unix-систем.","frontmatter":{"title":"Find-псевдонимы | Dotfiles","description":"Оптимизируйте поиск файлов с помощью псевдонимов на основе fd. Быстрый, цветной вывод и интуитивные команды для Unix-систем.","lang":"ru-RU","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Find-псевдонимы preview","canonical":"/ru/aliases/find/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Find-псевдонимы","pageType":"docs","schemaType":"WebPage","metaTitle":"Find-псевдонимы - Dotfiles (RU)","permalink":"/ru/aliases/find/","sidebar":true,"meta":[{"name":"keywords","content":"find aliases, fd command, file search, shell aliases, dotfiles, unix find"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Find-псевдонимы - Dotfiles"},{"name":"twitter:description","content":"Оптимизируйте поиск файлов с помощью псевдонимов на основе fd. Быстрый, цветной вывод и интуитивные команды для Unix-систем."},{"name":"og:title","content":"Find-псевдонимы - Dotfiles"},{"name":"og:description","content":"Оптимизируйте поиск файлов с помощью псевдонимов на основе fd. Быстрый, цветной вывод и интуитивные команды для Unix-систем."},{"name":"og:image:alt","content":"Dotfiles - Простой дизайн для вашей жизни в командной оболочке"},{"name":"og:locale","content":"ru_RU"}]},"headers":[],"relativePath":"ru/aliases/find/index.md","filePath":"ru/aliases/find/index.md","lastUpdated":1773010926000}'),i={name:"ru/aliases/find/index.md"};function c(r,t,n,l,s,f){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="find-псевдонимы" tabindex="-1">Find-псевдонимы <a class="header-anchor" href="#find-псевдонимы" aria-label="Permalink to &quot;Find-псевдонимы&quot;">​</a></h1><p>Мощные ярлыки поиска файлов с использованием fd, современной альтернативы find.</p><p><img src="https://kura.pro/dotfiles/v2/images/titles/title-dotfiles.svg" alt="Баннер Dotfiles"></p><h2 id="обзор" tabindex="-1">Обзор <a class="header-anchor" href="#обзор" aria-label="Permalink to &quot;Обзор&quot;">​</a></h2><p>Эти псевдонимы предоставляют упрощённый интерфейс к <code>fd</code>, быстрой и удобной альтернативе традиционной команде <code>find</code>. Определённые в <code>find.aliases.sh</code>, они автоматически загружаются chezmoi и предлагают цветной вывод, интуитивный синтаксис и запоминающиеся команды для распространённых операций поиска файлов.</p><p>Когда <code>fd</code> доступен в вашей системе, команда <code>find</code> автоматически использует <code>fd</code>, обеспечивая улучшенную производительность и более простой синтаксис по умолчанию.</p><h2 id="справочник" tabindex="-1">Справочник <a class="header-anchor" href="#справочник" aria-label="Permalink to &quot;Справочник&quot;">​</a></h2><h3 id="основные-команды" tabindex="-1">Основные команды <a class="header-anchor" href="#основные-команды" aria-label="Permalink to &quot;Основные команды&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Команда</th><th>Описание</th></tr></thead><tbody><tr><td><code>fd</code></td><td><code>fd --color always</code></td><td>Поиск файлов с цветным выводом</td></tr><tr><td><code>find</code></td><td><code>fd</code></td><td>Использовать fd как замену find по умолчанию</td></tr></tbody></table><h3 id="параметры-поиска" tabindex="-1">Параметры поиска <a class="header-anchor" href="#параметры-поиска" aria-label="Permalink to &quot;Параметры поиска&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Команда</th><th>Описание</th></tr></thead><tbody><tr><td><code>fda</code></td><td><code>fd --absolute-path</code></td><td>Показать результаты с абсолютными путями</td></tr><tr><td><code>fdc</code></td><td><code>fd --ignore-case</code></td><td>Выполнить поиск без учёта регистра</td></tr><tr><td><code>fdd</code></td><td><code>fd --list-details</code></td><td>Показать детальную информацию о файлах</td></tr><tr><td><code>fde</code></td><td><code>fd --extension</code></td><td>Фильтровать по расширению файла</td></tr><tr><td><code>fdf</code></td><td><code>fd --follow</code></td><td>Следовать символическим ссылкам при поиске</td></tr><tr><td><code>fdh</code></td><td><code>fd --hidden</code></td><td>Включить скрытые файлы в результаты</td></tr><tr><td><code>fdn</code></td><td><code>fd --glob</code></td><td>Сопоставлять файлы с glob-шаблонами</td></tr><tr><td><code>fdo</code></td><td><code>fd --owner</code></td><td>Фильтровать по владельцу файла</td></tr><tr><td><code>fds</code></td><td><code>fd --size</code></td><td>Фильтровать по размеру файла</td></tr><tr><td><code>fdu</code></td><td><code>fd --exclude</code></td><td>Исключить файлы, соответствующие шаблону</td></tr><tr><td><code>fdx</code></td><td><code>fd --exec</code></td><td>Выполнить команду для каждого результата</td></tr></tbody></table><h3 id="служебные-команды" tabindex="-1">Служебные команды <a class="header-anchor" href="#служебные-команды" aria-label="Permalink to &quot;Служебные команды&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Команда</th><th>Описание</th></tr></thead><tbody><tr><td><code>fdv</code></td><td><code>fd --version</code></td><td>Показать информацию о версии fd</td></tr></tbody></table>',13)])])}const u=d(i,[["render",c]]);export{m as __pageData,u as default};
